// Chunked upload: split file, initiate upload, upload all chunks, complete, return job_id
const CHUNK_SIZE = 50 * 1024 * 1024; // 50MB
const binary = await this.helpers.getBinaryDataBuffer(0, 'data');
const totalChunks = Math.ceil(binary.length / CHUNK_SIZE);
const filename = $input.item.json.body?.filename || 'upload.mp4';
const model = $input.item.json.body?.model || 'small';
const baseUrl = $env.TRANSCRIPTION_API_URL || 'https://transcript.fluximetry.com';

// Step 1: Initiate chunked upload
const initResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/api/v1/uploads`,
  body: {
    filename: filename,
    total_chunks: totalChunks,
    total_size_mb: Math.round(binary.length / 1024 / 1024 * 100) / 100,
    model: model,
    speaker_diarization: 'true'
  },
  json: true
});

const uploadId = initResponse.upload_id;

// Step 2: Upload each chunk
for (let i = 0; i < totalChunks; i++) {
  const start = i * CHUNK_SIZE;
  const end = Math.min(start + CHUNK_SIZE, binary.length);
  const chunkBuffer = binary.slice(start, end);

  const formData = new FormData();
  formData.append('chunk_index', String(i));
  formData.append('chunk', new Blob([chunkBuffer]), `chunk_${i}`);

  await this.helpers.httpRequest({
    method: 'POST',
    url: `${baseUrl}/api/v1/uploads/${uploadId}/chunks`,
    body: formData,
    headers: { 'Content-Type': 'multipart/form-data' },
    timeout: 60000
  });
}

// Step 3: Complete the upload
const completeResponse = await this.helpers.httpRequest({
  method: 'POST',
  url: `${baseUrl}/api/v1/uploads/${uploadId}/complete`,
  json: true,
  timeout: 30000
});

return [{
  json: {
    job_id: completeResponse.job_id,
    upload_id: uploadId,
    total_chunks: totalChunks,
    file_size_mb: Math.round(binary.length / 1024 / 1024 * 100) / 100
  }
}];
